const body = $input.first().json.body || $input.first().json;
const kbId = body.kbId;
const sourceUrl = body.sourceUrl;
const sourceBranch = body.sourceBranch || 'main';
const sourcePath = body.sourcePath || '';
const difyDatasetId = body.difyDatasetId;
const difyApiUrl = body.difyApiUrl || 'http://dify-api:5001';
const difyApiKey = body.difyApiKey || '';
const syncJobId = body.syncJobId;
const progressCallbackUrl = body.progressCallbackUrl;
const progressCallbackToken = body.progressCallbackToken || '';
const sourceToken = body.sourceToken || '';

if (!kbId || !sourceUrl || !difyDatasetId || !difyApiKey || !syncJobId) {
  throw new Error('Missing required sync parameters');
}

const match = sourceUrl.match(/gitlab\.com\/([^/]+(?:\/[^/]+)*)\/([^/]+)$/);
if (!match) throw new Error('Invalid GitLab URL: ' + sourceUrl);
const namespace = match[1];
const repo = match[2].replace(/\.git$/, '');
const projectPath = `${namespace}/${repo}`;
const encodedProjectPath = encodeURIComponent(projectPath);

return [{ json: {
  kbId, projectPath, encodedProjectPath,
  branch: sourceBranch,
  path: sourcePath,
  difyDatasetId, difyApiUrl, difyApiKey,
  syncJobId, progressCallbackUrl, progressCallbackToken, sourceToken,
  syncStartedAt: new Date().toISOString()
} }];

const TEXT_EXTS = new Set(['md','markdown','txt','html','htm','xml','csv']);
const items = $input.all();
const results = [];
for (let itemIndex = 0; itemIndex < items.length; itemIndex++) {
  const item = items[itemIndex];
  const { filePath, fileExt, difyApiUrl, difyDatasetId, difyApiKey, isUpdate, difyDocumentId } = item.json;
  const binaryFile = item.binary && item.binary.fileData ? item.binary.fileData : null;
  let docId = null, difyBatch = null, uploadError = null;
  try {
    if (!binaryFile) {
      uploadError = 'Fetch File Content did not return fileData for ' + filePath;
    } else {
      const fileBuffer = await this.helpers.getBinaryDataBuffer(itemIndex, 'fileData');
      if (TEXT_EXTS.has(fileExt)) {
        const text = fileBuffer.toString('utf8');
        const endpoint = isUpdate && difyDocumentId ? `/v1/datasets/${difyDatasetId}/documents/${difyDocumentId}/update_by_text` : `/v1/datasets/${difyDatasetId}/document/create_by_text`;
        const response = await this.helpers.httpRequest({
          method: 'POST',
          url: difyApiUrl + endpoint,
          headers: {
            Authorization: 'Bearer ' + difyApiKey,
            'Content-Type': 'application/json',
          },
          body: {
            name: filePath,
            text,
            indexing_technique: 'high_quality',
            process_rule: {
              mode: 'custom',
              rules: {
                pre_processing_rules: [
                  { id: 'remove_extra_spaces', enabled: true },
                  { id: 'remove_urls_emails', enabled: false },
                ],
                segmentation: { separator: '\n\n', max_tokens: 1000, chunk_overlap: 200 },
              },
            },
          },
          json: true,
          returnFullResponse: true,
        });
        const payload = response.body ?? response;
        docId = payload.document?.id ?? null;
        difyBatch = payload.batch ?? null;
        if (!docId || !difyBatch) {
          uploadError = payload.message || 'Dify did not return a document id and batch';
        }
      } else {
        const formData = {
          file: { value: fileBuffer, options: { filename: filePath } },
          data: JSON.stringify({
            indexing_technique: 'high_quality',
            process_rule: { mode: 'automatic' },
          })
        };
        const endpoint = isUpdate && difyDocumentId ? `/v1/datasets/${difyDatasetId}/documents/${difyDocumentId}/update_by_file` : `/v1/datasets/${difyDatasetId}/document/create_by_file`;
        const response = await this.helpers.httpRequest({
          method: 'POST',
          url: difyApiUrl + endpoint,
          headers: { Authorization: 'Bearer ' + difyApiKey },
          formData,
          json: true,
          returnFullResponse: true,
        });
        const payload = response.body ?? response;
        docId = payload.document?.id ?? null;
        difyBatch = payload.batch ?? null;
        if (!docId || !difyBatch) {
          uploadError = payload.message || 'Dify did not return a document id and batch';
        }
      }
    }
  } catch (e) {
    uploadError = e?.response?.body?.message || e?.message || String(e);
  }
  results.push({ json: { ...item.json, difyDocId: docId, difyBatch, uploadError, uploadMethod: TEXT_EXTS.has(fileExt) ? 'text' : 'file' } });
}
return results;

const response = $input.first().json || {};
const params = $('Parse Sync Params').first().json;

// Handle if the sync-diff node returned an error directly
if (response.error || response.message) {
  if (params.progressCallbackUrl) {
    const headers = { 'Content-Type': 'application/json' };
    if (params.progressCallbackToken) headers['X-Rag-Sync-Token'] = params.progressCallbackToken;
    this.helpers.httpRequest({
      method: 'POST',
      url: params.progressCallbackUrl,
      headers,
      body: {
        syncJobId: params.syncJobId,
        status: 'failed',
        errorMessage: response.error || response.message || 'Error communicating with gateway',
        logSeverity: 'ERROR',
      },
      json: true,
    }).catch(() => {});
  }
  throw new Error(response.error || response.message || 'Error communicating with gateway');
}

const files = response.files || [];

if (files.length === 0) {
  // If no files to update, report early completion and stop workflow
  if (params.progressCallbackUrl) {
    const headers = { 'Content-Type': 'application/json' };
    if (params.progressCallbackToken) headers['X-Rag-Sync-Token'] = params.progressCallbackToken;
    this.helpers.httpRequest({
      method: 'POST',
      url: params.progressCallbackUrl,
      headers,
      body: {
        syncJobId: params.syncJobId,
        status: 'completed',
        filesProcessed: 0,
        filesTotal: 0,
        step: {
          task: 'Skip Sync',
          stepName: 'skip_sync',
          status: 'completed',
          completedAt: new Date().toISOString(),
          message: 'No files needed updating or creating',
        },
        logMessage: 'Sync complete: No files modified since last sync',
        logSeverity: 'INFO',
      },
      json: true,
    }).catch(() => {});
  }
  return [];
}

return files.map((item, index) => ({
  json: {
    ...params,
    filePath: item.path,
    fileSha: item.sha,
    fileExt: (item.path.split('.').pop() || '').toLowerCase(),
    fileIndex: index + 1,
    totalFiles: files.length,
    encodedFilePath: encodeURIComponent(item.path),
    difyDocumentId: item.difyDocumentId || null,
    isUpdate: !!item.isUpdate
  }
}));

const items = $input.all();
const params = $('Parse Sync Params').first().json;
if (params.progressCallbackUrl) {
  const headers = { 'Content-Type': 'application/json' };
  if (params.progressCallbackToken) headers['X-Rag-Sync-Token'] = params.progressCallbackToken;
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: params.progressCallbackUrl,
      headers,
      body: {
        syncJobId: params.syncJobId,
        status: 'running',
        filesTotal: items.length,
        filesProcessed: 0,
        step: {
          task: 'Fetch File Tree',
          stepName: 'fetch_file_tree',
          status: 'completed',
          completedAt: new Date().toISOString(),
          message: 'Found ' + items.length + ' supported files',
        },
        logMessage: 'File tree ready: ' + items.length + ' files to upload',
      },
      json: true,
    });
  } catch {}
}
return items;

const TEXT_EXTS = new Set(['md','markdown','txt','html','htm','xml','csv']);
const items = $input.all();
const results = [];
for (let itemIndex = 0; itemIndex < items.length; itemIndex++) {
  const item = items[itemIndex];
  const { filePath, fileExt, difyApiUrl, difyDatasetId, difyApiKey, isUpdate, difyDocumentId } = item.json;
  const text = item.json.data;
  let docId = null, difyBatch = null, uploadError = null;
  try {
    if (!TEXT_EXTS.has(fileExt)) {
      uploadError = 'Unsupported file extension for current sync workflow: ' + fileExt;
    } else if (!text) {
      uploadError = 'Fetch File Content did not return data for ' + filePath;
    } else {
      const endpoint = isUpdate && difyDocumentId ? `/v1/datasets/${difyDatasetId}/documents/${difyDocumentId}/update_by_text` : `/v1/datasets/${difyDatasetId}/document/create_by_text`;
      const response = await this.helpers.httpRequest({
        method: 'POST',
        url: difyApiUrl + endpoint,
        headers: {
          Authorization: 'Bearer ' + difyApiKey,
          'Content-Type': 'application/json',
        },
        body: {
          name: filePath,
          text,
          indexing_technique: 'high_quality',
          process_rule: {
            mode: 'custom',
            rules: {
              pre_processing_rules: [
                { id: 'remove_extra_spaces', enabled: true },
                { id: 'remove_urls_emails', enabled: false },
              ],
              segmentation: { separator: '\n\n', max_tokens: 1000, chunk_overlap: 200 },
            },
          },
        },
        json: true,
        returnFullResponse: true,
      });
      const payload = response.body ?? response;
      docId = payload.document?.id ?? null;
      difyBatch = payload.batch ?? null;
      if (!docId || !difyBatch) {
        uploadError = payload.message || 'Dify did not return a document id and batch';
      }
    }
  } catch (e) {
    uploadError = e?.response?.body?.message || e?.message || String(e);
  }
  results.push({ json: { ...item.json, difyDocId: docId, difyBatch, uploadError, uploadMethod: 'text' } });
}
return results;

const items = $input.all();
const params = $('Parse Sync Params').first().json;
for (const item of items) {
  if (!params.progressCallbackUrl) continue;
  const headers = { 'Content-Type': 'application/json' };
  if (params.progressCallbackToken) headers['X-Rag-Sync-Token'] = params.progressCallbackToken;
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: params.progressCallbackUrl,
      headers,
      body: {
        syncJobId: params.syncJobId,
        status: 'running',
        filesProcessed: item.json.fileIndex,
        filesTotal: item.json.totalFiles,
        chunksProcessed: item.json.fileIndex,
        step: {
          task: 'Upload Files',
          stepName: item.json.uploadError ? 'upload_files' : 'upload_file_success',
          status: item.json.uploadError ? 'failed' : 'completed',
          message: item.json.fileIndex + '/' + item.json.totalFiles + ' processed',
          errorMessage: item.json.uploadError || undefined,
        },
        logMessage: 'Processed ' + item.json.filePath + (item.json.uploadError ? ' | ERROR: ' + item.json.uploadError : ''),
        logSeverity: item.json.uploadError ? 'ERROR' : 'INFO',
        difyDocumentId: item.json.difyDocId || undefined,
        filePath: item.json.filePath || undefined,
        fileSha: item.json.fileSha || undefined
      },
      json: true,
    });
  } catch {}
}
return items;
